async function executeHarpyGripAccBrace(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab.level||1));
  const mb=braceFamilyMasteryBonuses(ab);
  await doSpell('player',cfg.fx||'🦅');
  const down=(cfg.accDown?.[lv-1]||0)+Math.floor(mb.accRider||0);
  G.enemyStatus.accDebuff=(G.enemyStatus.accDebuff||0)+down;
  if(cfg.weakenChance?.[lv-1] && chance(cfg.weakenChance[lv-1])){ applyAilment('enemy','weaken',1); spawnFloat('enemy','🐔 Weaken!','fn-status'); }
  if(cfg.paraChance?.[lv-1] && chance(cfg.paraChance[lv-1]+(mb.paraRider||0))){ applyAilment('enemy','paralyzed',1); spawnFloat('enemy','⚡ Para!','fn-status'); }
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log}! Prey vision falters (−${down} ACC).`,'player-action');
}
function preparePlayerPhysicalPierceFromAbility(ab){
  if(!ab){ G._currentPiercePct=0; return; }
  const tmpl=getAbilityTemplateForUI(ab);
  const lv=Math.min(ab.level||1,4);
  let piercePct=(tmpl?.pierceDef||0)+(Number(ab.pierceDef)||0)+(lv>=2?5:0)+(lv>=3?5:0);
  if(BIRDS[G.player.birdKey]?.passive?.id==='passive_kiwi_burrow_sense' && !G._firstAttackUsed) piercePct+=10;
  const enCost=Number(tmpl?.energy ?? tmpl?.energyCost ?? ab?.energy ?? 1);
  if(BIRDS[G.player.birdKey]?.passive?.id==='passive_secretary_long_leg_reach' && enCost<=1) piercePct+=10;
  G._currentPiercePct=Math.max(Number(G._currentPiercePct)||0,piercePct);
}
/** Predator sheet: exact DEF-ignore % (then Kiwi first-attack / Secretary 1 EN passives). */
function preparePlayerPhysicalPierceExact(ab, basePct){
  let piercePct=Math.max(0,Math.floor(Number(basePct)||0));
  if(BIRDS[G.player.birdKey]?.passive?.id==='passive_kiwi_burrow_sense' && !G._firstAttackUsed) piercePct+=10;
  const tmpl=getAbilityTemplateForUI(ab);
  const enCost=Number(tmpl?.energy ?? tmpl?.energyCost ?? ab?.energy ?? 1);
  if(BIRDS[G.player.birdKey]?.passive?.id==='passive_secretary_long_leg_reach' && enCost<=1) piercePct+=10;
  G._currentPiercePct=Math.max(Number(G._currentPiercePct)||0,piercePct);
}
function predatorHybridPhysicalDamage(flat, atkPct, matkPct, ab){
  const fa=Math.max(0,Number(flat)||0);
  let atkVal=Math.max(0,Number(G.player.stats.atk||0));
  if(G.warcryActive) atkVal=Math.floor(atkVal*(1+G.warcryATK/100));
  if(G.sitAndWaitActive) atkVal=Math.floor(atkVal*1.25);
  if(G.tookieActive && G.playerStatus.tookie) atkVal=Math.floor(atkVal*(1+G.playerStatus.tookie.atkBonus/100));
  const atkCore=softenMainStatForCombat(atkVal)*COMBAT_OFFENSIVE_STAT_MULT;
  const atkRoll=roll(Math.max(1,Math.floor(atkCore*0.8)), Math.max(1,Math.floor(atkCore*1.2)));
  let matkVal=Math.max(0,Number(G.player.stats.matk||0));
  const matkCore=softenMainStatForCombat(matkVal)*COMBAT_OFFENSIVE_STAT_MULT;
  const matkRoll=roll(Math.max(1,Math.floor(matkCore*0.8)), Math.max(1,Math.floor(matkCore*1.2)));
  let base=fa+Math.floor(atkRoll*Number(atkPct||0))+Math.floor(matkRoll*Number(matkPct||0));
  if(G.playerStatus.weaken&&G.playerStatus.weaken>0) base=Math.floor(base*0.75);
  const __adm=(G.actionDamageHitsRemaining&&G.actionDamageHitsRemaining>0)?(G.actionDamageMult||1):1;
  let strikeAdd=0;
  if(G._pendingStrikeActionMods) strikeAdd=Number(G._pendingStrikeActionMods.multAdd)||0;
  base=Math.floor(base*(1+strikeAdd)*__adm);
  if((G.actionDamageHitsRemaining||0)>0){ G.actionDamageHitsRemaining=Math.max(0,G.actionDamageHitsRemaining-1); if(G.actionDamageHitsRemaining===0) G.actionDamageMult=1; }
  return Math.max(1,base);
}
function applyPredatorBleedHighChance(){
  if(chance(45)){ applyBleedStacksCap(1,1); spawnFloat('enemy','🩸 Bleed!','fn-poison'); }
}
function applyPredatorPoisonHighChance(){
  if(chance(45)){ applyAilment('enemy','poison',1); spawnFloat('enemy','☣ Poison!','fn-poison'); }
}
function applyPredatorPoisonMediumChance(){
  if(chance(40)){ applyAilment('enemy','poison',1); spawnFloat('enemy','☣ Poison!','fn-poison'); }
}
function applyEnemyBurningRefreshTurns(turns){
  const t=Math.max(1,Math.floor(Number(turns)||2));
  G.enemyStatus.burning={turns:t};
}
async function executePredatorSheetStrike(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab?.level||1));
  const mb=strikeFamilyMasteryBonuses(ab);
  const missBase=cfg.miss?.[lv-1]??10;
  const miss=cfg.cannotMiss?0:Math.max(0,missBase-getPlayerHitBonus(ab)-Math.floor(mb.missCut||0));
  if(!cfg.cannotMiss && chance(miss)){ await doMiss('player'); logMsg(`${cfg.log||cfg.name||ab?.id} missed!`,'miss'); return; }
  const flat=cfg.flat?.[lv-1]??0;
  const atkPct=cfg.statPct?.[lv-1]??0;
  const matkPct=cfg.matkPct?.[lv-1]??0;
  const pierceX=cfg.pierceExact?.[lv-1]??cfg.pierceExact??0;
  preparePlayerPhysicalPierceExact(ab,pierceX);
  let dmg=matkPct?predatorHybridPhysicalDamage(flat,atkPct,matkPct,ab):tankFlatStatPhysicalDamage(flat,'atk',atkPct,ab);
  let delayedExtra=0;
  if(cfg.consumeDelayed){
    const d=G.enemyStatus?.delayed;
    if(d&&d.dmg>0){ delayedExtra=d.dmg; delete G.enemyStatus.delayed; spawnFloat('enemy',`💥 +${delayedExtra}`,'fn-dmg'); }
    dmg+=delayedExtra;
  }
  const critFlat=(cfg.critChanceFlat?.[lv-1]||0)+Math.floor(mb.critBonus||0);
  const critDb=cfg.critDmgBonus?.[lv-1]||0;
  const prevG=critDb? (G.playerStatus.galahCritDmg||0):0;
  if(critDb) G.playerStatus.galahCritDmg=prevG+critDb;
  const isCrit=chance(Math.min(95,getPlayerCritChance(ab)+critFlat));
  const r=dealDamage('enemy',dmg,isCrit,false,ab);
  if(critDb) G.playerStatus.galahCritDmg=prevG;
  await doAttack('player','enemy',r);
  setHpBar('enemy',G.enemy.stats.hp,G.enemy.stats.maxHp);
  if(typeof cfg.afterHit==='function') await cfg.afterHit(lv,mb,r);
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log||cfg.name||ab?.id}! ${r.dmgDealt} dmg${delayedExtra?` (+${delayedExtra} delayed)`:''}.`,'player-action');
}
async function executePredatorSpdDodgeThisTurnUtility(ab, cfg){
  const lv=Math.max(1,Math.min(4,Number(ab?.level)||1));
  const spd=(cfg.spd&&cfg.spd[lv-1]!=null)?cfg.spd[lv-1]:(cfg.spdFlat??12);
  const dodge=(cfg.dodgePct&&cfg.dodgePct[lv-1]!=null)?cfg.dodgePct[lv-1]:(cfg.dodgeFlat??12);
  G.player.stats.spd=Math.min(20,(G.player.stats.spd||1)+spd);
  G.player._predatorUtilitySpdLoan=(G.player._predatorUtilitySpdLoan||0)+spd;
  G.playerStatus.humDodge={bonus:dodge, turns:1};
  await doSpell('player',cfg.fx||'🪶');
  renderStatuses('player-status',G.playerStatus);
  logMsg(cfg.log||`+${spd} SPD, +${dodge}% dodge (this turn, refresh).`,'player-action');
}
async function executePredatorAtkMdefThisTurnUtility(ab, cfg){
  const lv=Math.max(1,Math.min(4,Number(ab?.level)||1));
  const atkB=(cfg.atk&&cfg.atk[lv-1]!=null)?cfg.atk[lv-1]:(cfg.atkFlat??12);
  const mdfB=(cfg.mdef&&cfg.mdef[lv-1]!=null)?cfg.mdef[lv-1]:(cfg.mdefFlat??10);
  G.player.stats.atk=(G.player.stats.atk||0)+atkB;
  G.player.stats.mdef=(G.player.stats.mdef||0)+mdfB;
  G.player._predatorAtkThisTurnLoan=(G.player._predatorAtkThisTurnLoan||0)+atkB;
  G.player._predatorMdefThisTurnLoan=(G.player._predatorMdefThisTurnLoan||0)+mdfB;
  await doSpell('player',cfg.fx||'🪶');
  renderStatuses('player-status',G.playerStatus);
  logMsg(cfg.log||`+${atkB} ATK, +${mdfB} MDEF (this turn, refresh).`,'player-action');
}
/** Sheet-style physical: flat + rolled stat band × pct (ATK/DEF). Mirrors pdmg weaken / flyby / strike tempo where applicable. */
function tankFlatStatPhysicalDamage(flat, statKey, statPct, ab){
  const sk=String(statKey||'atk').toLowerCase();
  let statVal=Math.max(0,Number(G.player.stats[sk]||0));
  if(sk==='atk'){
    if(G.warcryActive) statVal=Math.floor(statVal*(1+G.warcryATK/100));
    if(G.sitAndWaitActive) statVal=Math.floor(statVal*1.25);
    if(G.tookieActive && G.playerStatus.tookie) statVal=Math.floor(statVal*(1+G.playerStatus.tookie.atkBonus/100));
  }
  const effCore=softenMainStatForCombat(statVal)*COMBAT_OFFENSIVE_STAT_MULT;
  const rolled=roll(Math.max(1,Math.floor(effCore*0.8)), Math.max(1,Math.floor(effCore*1.2)));
  let base=Math.floor(Number(flat)||0)+Math.floor(rolled*Number(statPct||0));
  if(G.playerStatus.weaken&&G.playerStatus.weaken>0) base=Math.floor(base*0.75);
  const __adm=(G.actionDamageHitsRemaining&&G.actionDamageHitsRemaining>0)?(G.actionDamageMult||1):1;
  let strikeAdd=0;
  if(G._pendingStrikeActionMods) strikeAdd=Number(G._pendingStrikeActionMods.multAdd)||0;
  base=Math.floor(base*(1+strikeAdd)*__adm);
  if((G.actionDamageHitsRemaining||0)>0){ G.actionDamageHitsRemaining=Math.max(0,G.actionDamageHitsRemaining-1); if(G.actionDamageHitsRemaining===0) G.actionDamageMult=1; }
  return Math.max(1,base);
}
function applyTankFlatDefBoostRefresh(amt, turns=1){
  const a=Math.max(0,Math.floor(amt));
  const t=Math.max(1,turns|0);
  const prev=G.playerStatus.defBoost;
  if(prev&&prev.amt) G.player.stats.def=Math.max(0,(G.player.stats.def||0)-prev.amt);
  G.player.stats.def=(G.player.stats.def||0)+a;
  G.playerStatus.defBoost={amt:a, turns:t};
}
function applyTankFlatMdefBoostRefresh(amt, turns=1){
  const a=Math.max(0,Math.floor(amt));
  const t=Math.max(1,turns|0);
  const prev=G.playerStatus.tankTempMdef;
  if(prev&&prev.amt) G.player.stats.mdef=Math.max(0,(G.player.stats.mdef||0)-prev.amt);
  G.player.stats.mdef=(G.player.stats.mdef||0)+a;
  G.playerStatus.tankTempMdef={amt:a, turns:t};
}
function applyEnemyAccPenaltyRefresh(amt, turns=2){
  const a=Math.max(0,Math.floor(amt));
  const t=Math.max(1,turns|0);
  const prev=G.enemyStatus.bruiserAccMark;
  if(prev&&(prev.turns||0)>0) G.enemyStatus.accDebuff=Math.max(0,(G.enemyStatus.accDebuff||0)-(prev.amt||0));
  G.enemyStatus.accDebuff=(G.enemyStatus.accDebuff||0)+a;
  G.enemyStatus.bruiserAccMark={amt:a, turns:t};
}
function applyEnemyWeakenRefreshTurns(turns=1){
  G.enemyStatus.weaken=Math.max(G.enemyStatus.weaken||0, Math.max(1,turns|0));
}
function applyBleedStacksCap(stacks, cap=1){
  const status=G.enemyStatus;
  if(!status.bleed) status.bleed={stacks:0,turns:3};
  const want=Math.min(Math.max(1,Math.floor(stacks||1)), Math.max(1,cap|0));
  status.bleed.stacks=want;
  status.bleed.turns=3;
}
async function executeTankSheetStrike(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab?.level||1));
  const mb=strikeFamilyMasteryBonuses(ab);
  const miss=Math.max(0,(cfg.miss?.[lv-1]??10)-getPlayerHitBonus(ab)-Math.floor(mb.missCut||0));
  if(chance(miss)){ await doMiss('player'); logMsg(`${cfg.log||cfg.name||ab?.id} missed!`,'miss'); return; }
  const flat=cfg.flat?.[lv-1]??0;
  const pct=cfg.statPct?.[lv-1]??0;
  const statKey=cfg.statKey||'atk';
  const pierceExtra=(cfg.pierce?.[lv-1]??0)+(mb.pierce||0);
  preparePlayerPhysicalPierceFromAbility({...ab,pierceDef:pierceExtra});
  let dmg=tankFlatStatPhysicalDamage(flat, statKey, pct, ab);
  const critFlat=(cfg.critChanceFlat?.[lv-1]||0)+Math.floor(mb.critBonus||0);
  const critDb=cfg.critDmgBonus?.[lv-1]||0;
  const prevG=critDb? (G.playerStatus.galahCritDmg||0):0;
  if(critDb) G.playerStatus.galahCritDmg=prevG+critDb;
  const isCrit=chance(Math.min(95,getPlayerCritChance(ab)+critFlat));
  const r=dealDamage('enemy',dmg,isCrit,false,ab);
  if(critDb) G.playerStatus.galahCritDmg=prevG;
  await doAttack('player','enemy',r);
  setHpBar('enemy',G.enemy.stats.hp,G.enemy.stats.maxHp);
  if(typeof cfg.afterHit==='function') await cfg.afterHit(lv,mb,r);
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log||cfg.name||ab?.id}! ${r.dmgDealt} dmg.`,'player-action');
}
async function executeTankHonkGuardUtility(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab.level||1));
  await doSpell('player',cfg.fx||'🛡');
  applyTankFlatDefBoostRefresh(cfg.defAmt?.[lv-1]??10, cfg.defTurns?.[lv-1]??1);
  renderStatuses('player-status',G.playerStatus);
  logMsg(`${cfg.log||ab.name||'Guard'}! +${cfg.defAmt?.[lv-1]??10} DEF (${cfg.defTurns?.[lv-1]??1}t, refresh).`,'player-action');
}
async function executeTankHealPlusBuffs(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab.level||1));
  await doSpell('player',cfg.fx||'💚');
  const frac=cfg.healFrac?.[lv-1]??0.14;
  let heal=Math.max(1,Math.floor((G.player.stats.maxHp||1)*frac));
  if(BIRDS[G.player?.birdKey]?.passive?.id==='passive_pelican_deep_pouch') heal=Math.floor(heal*1.1);
  G.player.stats.hp=Math.min(G.player.stats.maxHp,G.player.stats.hp+heal);
  await doHeal('player',heal);
  setHpBar('player',G.player.stats.hp,G.player.stats.maxHp);
  if(cfg.mdefAmt?.[lv-1]) applyTankFlatMdefBoostRefresh(cfg.mdefAmt[lv-1], cfg.mdefTurns?.[lv-1]??1);
  if(cfg.defAmt?.[lv-1]) applyTankFlatDefBoostRefresh(cfg.defAmt[lv-1], cfg.defTurns?.[lv-1]??1);
  renderStatuses('player-status',G.playerStatus);
  logMsg(`${cfg.log||ab.name||'Recovery'}! +${heal} HP.`,'player-action');
}
async function executeBruiserCall(ab, cfg){
  await doSpell('player',cfg.fx||'📢');
  if(cfg.applyWeaken) applyEnemyWeakenRefreshTurns(cfg.weakenTurns||1);
  if(cfg.spdBonus){
    const b=cfg.spdBonus;
    G.player.stats.spd=Math.min(20,(G.player.stats.spd||1)+b);
    G.playerStatus.bruiserCallSpd={bonus:b, turns:Math.max(1,cfg.spdTurns||1)};
  }
  if(cfg.accPenaltyAmt) applyEnemyAccPenaltyRefresh(cfg.accPenaltyAmt, cfg.accPenaltyTurns||2);
  renderStatuses('player-status',G.playerStatus);
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log||ab.name||'Call'}!`,'player-action');
}
async function executeShoebillSwampStance(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab.level||1));
  const mb=getShoebillMasteryBonuses(ab);
  await doSpell('player',cfg.fx||'🦤');
  const dodge=(cfg.humDodge?.[lv-1]||22)+Math.floor(mb.dodgeHumRider||0);
  let turns=cfg.humTurns?.[lv-1]||2;
  if(cfg.extraHumTurnIfControl&&getSlotMasteryProfile(getAbilitySkillSlot(G.player,ab)||{}).control>0 && lv>=3) turns+=1;
  G.playerStatus.humDodge={bonus:dodge, turns};
  if(cfg.slowSpd?.[lv-1]) applyEnemySlow(cfg.slowSpd[lv-1], cfg.slowDodge?.[lv-1]||8, cfg.slowTurns?.[lv-1]||2);
  if(cfg.fearChance?.[lv-1] && chance(cfg.fearChance[lv-1]+(mb.fearRider||0))){ applyAilment('enemy','feared',1); spawnFloat('enemy','😨 Fear!','fn-status'); }
  renderStatuses('player-status',G.playerStatus);
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log}!`,'player-action');
}
async function executeGooseStrikeAction(ab, config={}){
  const lv=Math.max(1, Math.min(4, ab?.level||1));
  const mb=strikeFamilyMasteryBonuses(ab);
  const miss=Math.max(0, (config.miss?.[lv-1] ?? 0) - getPlayerHitBonus(ab) - Math.floor(mb.missCut||0));
  if(chance(miss)){ await doMiss('player'); logMsg(`${config.name||ab?.name||ab?.id} missed!`,'miss'); return; }
  let mult=(config.mult?.[lv-1] ?? 1) + (mb.dmg||0);
  if(config.bonusVs==='bleed' && (G.enemyStatus.bleed?.stacks||0)>0) mult += (config.bonus?.[lv-1] ?? 0);
  if(config.bonusVs==='feared' && (G.enemyStatus.feared||0)>0) mult += (config.bonus?.[lv-1] ?? 0);
  if(config.bonusVs==='weakened' && (G.enemyStatus.weaken||0)>0) mult += (config.bonus?.[lv-1] ?? 0);
  if(config.bonusVs==='guard' && ((G.enemyStatus.defending||0)>0 || (G.enemyStatus.exposedGuard?.pct||0)>0)) mult += (config.bonus?.[lv-1] ?? 0);
  if(config.bonusVs==='low_hp' && G.enemy.stats.hp <= Math.floor((G.enemy.stats.maxHp||1) * (config.lowHpThreshold || 0.5))) mult += (config.bonus?.[lv-1] ?? 0) + (mb.lowHpRider||0);
  if(config.bonusVs==='compromised' && gooseEnemyCompromised()) mult += (config.bonus?.[lv-1] ?? 0) + (mb.readRider||0);
  const pierceBase=(config.pierce?.[lv-1] ?? 0) + (mb.pierce||0);
  const prox={...ab, pierceDef:pierceBase};
  const critExtra=(config.critBonus?.[lv-1]||0)+(mb.critBonus||0);
  const isCrit=chance(Math.min(95,getPlayerCritChance(ab)+critExtra));
  const dmgCore=config.useBodyScaling ? pdmgWithAlternateScaling(mult, ab) : pdmg(mult, prox);
  const r=dealDamage('enemy',dmgCore,isCrit,false,config.useBodyScaling?ab:prox);
  await doAttack('player','enemy',r);
  setHpBar('enemy',G.enemy.stats.hp,G.enemy.stats.maxHp);
  if(config.bleedChance?.[lv-1] && chance(config.bleedChance[lv-1]+(mb.bleedRider||0))){ applyAilment('enemy','bleed',1); spawnFloat('enemy','🩸 Bleed!','fn-poison'); }
  if(config.weakenChance?.[lv-1] && chance(config.weakenChance[lv-1]+(mb.weakenRider||0))){ applyAilment('enemy','weaken',1); spawnFloat('enemy','🐔 Weaken!','fn-status'); }
  if(config.fearChance?.[lv-1] && chance(config.fearChance[lv-1]+(mb.fearRider||0))){ applyAilment('enemy','feared',1); spawnFloat('enemy','😨 Fear!','fn-status'); }
  if(config.paraChance?.[lv-1] && chance(config.paraChance[lv-1]+(mb.paraRider||0))){ applyAilment('enemy','paralyzed',1); spawnFloat('enemy','⚡ Para!','fn-status'); }
  if(config.accDown?.[lv-1]) G.enemyStatus.accDebuff=(G.enemyStatus.accDebuff||0)+config.accDown[lv-1]+Math.floor(mb.accRider||0);
  if(config.defBreak?.[lv-1]) peregrineApplyDefBreak(config.defBreak[lv-1]+(mb.defBreakRider||0), config.defBreakTurns?.[lv-1]||2);
  if(config.applyExpose?.[lv-1]){
    G.enemyStatus.exposedGuard={turns:config.exposeTurns?.[lv-1]||2,pct:config.applyExpose[lv-1]};
    G.enemyStatus.defending=0;
    spawnFloat('enemy','🎯 Exposed!','fn-status');
  }
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${config.log||config.name||ab?.name||ab?.id}! ${r.dmgDealt} dmg.`, 'player-action');
}
async function executeGooseHonkPhysical(ab, cfg){
  const lv=Math.max(1,Math.min(4,ab.level||1));
  const mb=G.player?.birdKey==='goose'?getGooseMasteryBonuses(ab):{};
  const miss=Math.max(0,(cfg.miss?.[lv-1]??22)-getPlayerHitBonus(ab));
  if(chance(miss)){await doMiss('player');logMsg(`${cfg.log} missed!`,'miss');return;}
  let mult=(cfg.mult?.[lv-1]??1)+(mb.dmg||0);
  if(cfg.bonusVs==='feared' && (G.enemyStatus.feared||0)>0) mult += (cfg.bonus?.[lv-1]??0);
  const prox={...ab,pierceDef:cfg.pierce?.[lv-1]??0};
  const r=dealDamage('enemy',pdmg(mult,prox),chance(getPlayerCritChance(ab)),false,prox);
  await doAttack('player','enemy',r);
  setHpBar('enemy',G.enemy.stats.hp,G.enemy.stats.maxHp);
  if(cfg.fearChance?.[lv-1] && chance(cfg.fearChance[lv-1]+(mb.fearRider||0))){ applyAilment('enemy','feared',1); spawnFloat('enemy','😨 Fear!','fn-status'); }
  if(cfg.weakenChance?.[lv-1] && chance(cfg.weakenChance[lv-1]+(mb.weakenRider||0))){ applyAilment('enemy','weaken',1); spawnFloat('enemy','🐔 Weaken!','fn-status'); }
  if(cfg.accDown?.[lv-1]) G.enemyStatus.accDebuff=(G.enemyStatus.accDebuff||0)+cfg.accDown[lv-1]+Math.floor(mb.accRider||0);
  if(cfg.paraChance?.[lv-1] && chance(cfg.paraChance[lv-1])){ applyAilment('enemy','paralyzed',1); spawnFloat('enemy','⚡ Para!','fn-status'); }
  renderStatuses('enemy-status',G.enemyStatus);
  logMsg(`${cfg.log}! ${r.dmgDealt} dmg.`,'player-action');
}
