    if(spellAilmentRoll([25,30,35,40][lv-1],false)) G.enemyStatus.feared=(G.enemyStatus.feared||0)+1;
    await doSpell('enemy','🎼 ASTRAL!'); renderStatuses('enemy-status',G.enemyStatus);
